// Expected body: {customer_name, customer_email, customer_gstin?, customer_address, line_items: [{name, qty, rate, sac?}], notes?, due_days?}
const b = $input.first().json.body;
const sub = b.line_items.reduce((s, i) => s + i.qty * i.rate, 0);
const gstRate = (b.customer_gstin && b.customer_gstin.startsWith('07')) ? {cgst: 0.09, sgst: 0.09, igst: 0} : {cgst: 0, sgst: 0, igst: 0.18}; // 07 = Delhi
const cgst = sub * gstRate.cgst;
const sgst = sub * gstRate.sgst;
const igst = sub * gstRate.igst;
const total = sub + cgst + sgst + igst;
const due = new Date(); due.setDate(due.getDate() + (b.due_days || 14));
return { json: {
  ...b,
  invoice_number: 'AICS-' + new Date().toISOString().slice(0,10).replace(/-/g,'') + '-' + Math.floor(Math.random()*9000+1000),
  invoice_date: new Date().toISOString().slice(0,10),
  due_date: due.toISOString().slice(0,10),
  subtotal: sub, cgst, sgst, igst, total,
  sac_default: '998313',
  supplier: { name: 'AICloudStrategist (Sole Proprietorship)', email: 'support@aicloudstrategist.com', gstin: '<TBD>', address: 'Delhi/NCR, India' }
}};

